+    #[test]
+    fn spawn_bounded_empty_tasks() {
+        let runtime = CxRuntimeBuilder::current_thread()
+            .build()
+            .expect("runtime");
+        let cx = for_testing();
+        let handle = runtime.handle();
+
+        let results: Vec<i32> = runtime.block_on(async {
